  const MIN_REPEAT_MS = 350;

  function safe(fn, fallback){ try { return fn(); } catch (_) { return fallback; } }
  function chars(){ return safe(() => typeof charactersInCurrentCampaign === 'function' ? charactersInCurrentCampaign() : [], []); }
