    const tabs = dialog.querySelector('.od193-editor-tabs');
    const body = dialog.querySelector('.od193-editor-body');
    if (!tabs || !body) return;
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.dataset.od193EditorTab = 'owlbear';
    btn.textContent = 'Mapa';
